async (intermediate) => {
  const delay = {{ delay }} || 3000;
  const totalMs = delay + Math.floor(Math.random() * delay);
  let scrollDir = 1;
  let scrollSpeed = 0.8 + Math.random() * 0.7;
  let sameDirCount = 0;
  const start = Date.now();
  while (Date.now() - start < totalMs) {
    const remaining = totalMs - (Date.now() - start);
    const r = Math.random();
    if (r < 0.5) {
      sameDirCount++;
      if (sameDirCount > 2 + Math.floor(Math.random() * 4)) {
        scrollDir *= -1;
        sameDirCount = 0;
        scrollSpeed = 0.6 + Math.random() * 0.9;
      }
      const step = Math.floor((500 + Math.random() * 1500) * scrollSpeed) * scrollDir;
      window.scrollBy({top: step, behavior: 'smooth'});
      await new Promise(res => setTimeout(res, 300 + Math.floor(Math.random() * 600)));
    } else {
      const pause = 1000 + Math.floor(Math.random() * 3000);
      await new Promise(res => setTimeout(res, Math.min(pause, remaining)));
    }
    await new Promise(res => setTimeout(res, Math.min(remaining, 200 + Math.floor(Math.random() * 500))));
  }
}
